plantumlCode:
@startuml
scale max 1890x2917

partition "Posture Sensor Array (200)" {
  start
  :Detect posture data;
}

partition "Processing Unit (400)" {
  :Receive posture data;
  :Analyze posture data;
  if (Posture incorrect?) then (yes)
    :Generate alert signal;
  else (no)
    stop
  endif
}

partition "Alert Module (100)" {
  :Receive alert signal;
  :Activate alert mechanism;
  stop
}

@enduml
